340	double eval_lookahead(const GameState& state_after_tilt, int turn_T_of_candy_just_processed, int depth_remaining) {
341	    if (depth_remaining == 0 || turn_T_of_candy_just_processed == NUM_TURNS) { 
342	        return state_after_tilt.evaluate();
343	    }
344	
345	    int num_empty = state_after_tilt.count_empty_cells();
346	    if (num_empty == 0) { 
347	        return state_after_tilt.evaluate();
348	    }
349	
350	    int next_candy_flavor = G_FLAVOR_SEQUENCE[turn_T_of_candy_just_processed]; 
351	    int sample_count_param_idx = MAX_LOOKAHEAD_DEPTH - depth_remaining;
352	    int sample_count_this_depth = NUM_SAMPLES_CONFIG[sample_count_param_idx];
353	    int actual_num_samples = std::min(sample_count_this_depth, num_empty);
354	    
355	    if (actual_num_samples == 0) { 
356	         return state_after_tilt.evaluate(); 
357	    }
358	
359	    double sum_over_sampled_placements = 0.0;
360	    for (int s = 0; s < actual_num_samples; ++s) {
361	        int p_val_1_indexed_sample;
362	        if (actual_num_samples == num_empty) { 
363	            p_val_1_indexed_sample = s + 1; 
364	        } else { 
365	            p_val_1_indexed_sample = rng.uniform_int(1, num_empty); 
366	        }
367	        
368	        GameState S_after_placement = state_after_tilt; 
369	        std::pair<int, int> candy_loc = S_after_placement.find_pth_empty_cell(p_val_1_indexed_sample);
370	        S_after_placement.place_candy(candy_loc.first, candy_loc.second, next_candy_flavor);
371	        S_after_placement.turn_num_1_indexed = turn_T_of_candy_just_processed + 1; 
372	
373	        double max_eval_for_this_placement = std::numeric_limits<double>::lowest();
374	        for (int dir_idx_next_tilt = 0; dir_idx_next_tilt < NUM_DIRECTIONS; ++dir_idx_next_tilt) {
375	            GameState S_after_next_tilt = S_after_placement; 
376	            S_after_next_tilt.apply_tilt(dir_idx_next_tilt);
377	            double val = eval_lookahead(S_after_next_tilt, S_after_placement.turn_num_1_indexed, depth_remaining - 1);
378	            if (val > max_eval_for_this_placement) {
379	                max_eval_for_this_placement = val;
380	            }
381	        }
382	        sum_over_sampled_placements += max_eval_for_this_placement;
383	    }
384	    
385	    return sum_over_sampled_placements / actual_num_samples;
386	}
