389	void initialize_global_data() {
390	    G_flavor_total_counts.fill(0);
391	    for (int t = 0; t < NUM_TURNS; ++t) {
392	        std::cin >> G_FLAVOR_SEQUENCE[t];
393	        G_flavor_total_counts[G_FLAVOR_SEQUENCE[t]]++;
394	    }
395	
396	    G_flavor_active.fill(false);
397	    std::vector<std::pair<int, int>> sorter_flavor_count_id; 
398	    for (int fl = 1; fl <= NUM_FLAVORS; ++fl) {
399	        if (G_flavor_total_counts[fl] > 0) {
400	            G_flavor_active[fl] = true;
401	            sorter_flavor_count_id.push_back({G_flavor_total_counts[fl], fl});
402	        }
403	    }
404	    std::sort(sorter_flavor_count_id.begin(), sorter_flavor_count_id.end(), 
405	        [](const std::pair<int, int>& a, const std::pair<int, int>& b) {
406	        if (a.first != b.first) {
407	            return a.first > b.first; 
408	        }
409	        return a.second < b.second; 
410	    });
411	
412	    std::vector<int> active_flavor_ids_sorted_by_priority;
413	    for(const auto& p : sorter_flavor_count_id) {
414	        active_flavor_ids_sorted_by_priority.push_back(p.second);
415	    }
416	    
417	    std::vector<int> assigned_widths(NUM_FLAVORS + 1, 0);
418	    int total_assigned_width_sum = 0;
419	
420	    if (!active_flavor_ids_sorted_by_priority.empty()) {
421	        double total_candies_for_proportion = 0;
422	        for(int fl_id : active_flavor_ids_sorted_by_priority) { 
423	            total_candies_for_proportion += G_flavor_total_counts[fl_id];
424	        }
425	        if (total_candies_for_proportion == 0) total_candies_for_proportion = 1; 
426	
427	        for (int fl_id : active_flavor_ids_sorted_by_priority) {
428	            assigned_widths[fl_id] = static_cast<int>(std::floor(
429	                static_cast<double>(GRID_SIZE) * G_flavor_total_counts[fl_id] / total_candies_for_proportion
430	            ));
431	            total_assigned_width_sum += assigned_widths[fl_id];
432	        }
433	
434	        int remaining_width_to_assign = GRID_SIZE - total_assigned_width_sum;
435	        for (int i = 0; i < remaining_width_to_assign; ++i) {
436	            assigned_widths[active_flavor_ids_sorted_by_priority[i % active_flavor_ids_sorted_by_priority.size()]]++;
437	        }
438	    }
439	
440	    int current_col_start = 0;
441	    for (int fl_id_in_sorted_order : active_flavor_ids_sorted_by_priority) { 
442	        if (assigned_widths[fl_id_in_sorted_order] > 0) {
443	            G_target_col_ranges[fl_id_in_sorted_order] = {current_col_start, current_col_start + assigned_widths[fl_id_in_sorted_order] - 1};
444	            current_col_start += assigned_widths[fl_id_in_sorted_order];
445	        } else { 
446	            G_target_col_ranges[fl_id_in_sorted_order] = {current_col_start, current_col_start - 1};
447	        }
448	    }
449	    
450	    for (int fl = 1; fl <= NUM_FLAVORS; ++fl) {
451	        if (!G_flavor_active[fl]) { 
452	            G_target_col_ranges[fl] = {0, -1}; 
453	        }
454	    }
455	}
